 */

/**
 * Image-text-to-text pipeline using an `AutoModelForImageTextToText`. This pipeline generates text
 * from an image and a text prompt, enabling tasks such as visual question answering, image-grounded
 * dialogue, and instruction-following with visual context.
 *
 * **Example:** Answer a question about an image w/ `Xenova/llava-1.5-7b-hf`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'Xenova/llava-1.5-7b-hf');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await pipe(url, 'How many cats are in this image?');
 * // [{ generated_text: 'There are two cats in this image.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(image, text, generate_kwargs = {}) {

        // Preprocess the input image
        const preparedImage = (await prepareImages(image))[0];
        const { pixel_values } = await this.processor(preparedImage);

        // Tokenize the text prompt
        const text_inputs = this.tokenizer(text, {
            padding: true,
            truncation: true,
        });

        // Generate output tokens from both visual and textual inputs
        const output = await this.model.generate({
            inputs: text_inputs.input_ids,
            pixel_values,
            attention_mask: text_inputs.attention_mask,
            ...generate_kwargs,
        });

        // Decode the generated token IDs to text
        const decoded = this.tokenizer.batch_decode(/** @type {Tensor} */(output), {
            skip_special_tokens: true,
        });

        return decoded.map(x => ({ generated_text: x.trim() }));
    }
}

